const testCase = $('Batch of 5').item.json;
const response = $input.item.json;
const results = response.body || response;
const expected = testCase.expected;
const failures = [];
let passed = true;

function checkRange(actual, range, label) {
  if (actual === undefined || actual === null) {
    failures.push(`${label}: missing value`);
    return false;
  }
  if (actual < range[0] || actual > range[1]) {
    failures.push(`${label}: ${actual.toFixed(4)} not in [${range[0]}, ${range[1]}]`);
    return false;
  }
  return true;
}

// Check impedance for solve/mom types
if (testCase.type === 'solve' || testCase.type === 'mom') {
  if (expected.z_re) {
    const z_re = results.impedance?.real ?? results.z_re ?? results.input_impedance?.real;
    if (!checkRange(z_re, expected.z_re, 'Z_re')) passed = false;
  }
  if (expected.z_im) {
    const z_im = results.impedance?.imag ?? results.z_im ?? results.input_impedance?.imag;
    if (!checkRange(z_im, expected.z_im, 'Z_im')) passed = false;
  }
  if (expected.gain_dbi) {
    const gain = results.gain_dbi ?? results.max_gain_dbi ?? results.gain;
    if (!checkRange(gain, expected.gain_dbi, 'Gain')) passed = false;
  }
}

// Check sweep results
if (testCase.type === 'sweep') {
  if (expected.resonance_mhz) {
    const res_freq = (results.resonance_frequency ?? results.resonant_frequency ?? 0) / 1e6;
    if (!checkRange(res_freq, expected.resonance_mhz, 'Resonance MHz')) passed = false;
  }
  if (expected.min_s11_db) {
    const min_s11 = results.min_s11_db ?? results.s11_min ?? results.min_s11 ?? 0;
    if (!checkRange(min_s11, expected.min_s11_db, 'Min S11')) passed = false;
  }
  if (expected.bw_10db_mhz) {
    const bw = (results.bandwidth_10db ?? results.bandwidth ?? 0) / 1e6;
    if (!checkRange(bw, expected.bw_10db_mhz, 'BW -10dB MHz')) passed = false;
  }
  // VSWR check: at resonance should be < 3
  if (results.s11_db) {
    const s11arr = results.s11_db;
    const minS11 = Math.min(...s11arr);
    const mag = Math.pow(10, minS11 / 20);
    const vswr = (1 + mag) / (1 - Math.min(mag, 0.9999));
    if (vswr > 3) {
      failures.push('VSWR at resonance: ' + vswr.toFixed(2) + ' > 3');
      passed = false;
    }
  }
}

// Check pattern results
if (testCase.type === 'pattern') {
  if (expected.max_gain_dbi) {
    const gain = results.max_gain_dbi ?? results.max_gain ?? results.peak_gain ?? 0;
    if (!checkRange(gain, expected.max_gain_dbi, 'Max Gain')) passed = false;
  }
  // Gain must be > 0 for directional antennas
  const gain = results.max_gain_dbi ?? results.max_gain ?? 0;
  if (gain <= 0 && expected.pattern_type !== 'isotropic') {
    failures.push('Gain <= 0 dBi for non-isotropic antenna: ' + gain.toFixed(2));
    passed = false;
  }
}

return [{
  json: {
    test_name: testCase.name,
    type: testCase.type,
    passed,
    failures,
    expected,
    actual_summary: {
      z_re: results.impedance?.real ?? results.z_re,
      z_im: results.impedance?.imag ?? results.z_im,
      gain_dbi: results.gain_dbi ?? results.max_gain_dbi,
      s11_db: results.s11_db ?? results.min_s11_db
    },
    raw_response: results
  }
}];

const allResults = $input.all().map(i => i.json);
const total = allResults.length;
const passed = allResults.filter(r => r.passed).length;
const failed = allResults.filter(r => !r.passed);
const passRate = ((passed / total) * 100).toFixed(1);

const summary = {
  timestamp: new Date().toISOString(),
  total_tests: total,
  passed,
  failed: total - passed,
  pass_rate: `${passRate}%`,
  status: failed.length === 0 ? 'ALL_PASS' : 'REGRESSION_DETECTED',
  failures: failed.map(f => ({
    test: f.test_name,
    type: f.type,
    issues: f.failures,
    actual: f.actual_summary
  })),
  results_by_type: {
    solve: allResults.filter(r => r.type === 'solve'),
    sweep: allResults.filter(r => r.type === 'sweep'),
    pattern: allResults.filter(r => r.type === 'pattern'),
    mom: allResults.filter(r => r.type === 'mom')
  }
};

return [{ json: summary }];

