const summary = $('Generate Summary').item.json;
const aiAnalysis = $('Claude Analyze Failures').item.json.output || 'No AI analysis';

const report = [
  '# PROMIN Antenna Studio — Regression Test Report',
  '',
  `**Date:** ${summary.timestamp}`,
  `**Status:** ${summary.status}`,
  `**Pass Rate:** ${summary.pass_rate} (${summary.passed}/${summary.total_tests})`,
  '',
  '## Summary',
  '',
  `| Metric | Value |`,
  `|--------|-------|`,
  `| Total Tests | ${summary.total_tests} |`,
  `| Passed | ${summary.passed} |`,
  `| Failed | ${summary.failed} |`,
  '',
];

if (summary.failures.length > 0) {
  report.push('## Failures', '');
  for (const f of summary.failures) {
    report.push(`### ${f.test} (${f.type})`);
    report.push(`- Issues: ${f.issues.join(', ')}`);
    report.push(`- Actual: Z_re=${f.actual?.z_re}, Z_im=${f.actual?.z_im}, Gain=${f.actual?.gain_dbi} dBi`);
    report.push('');
  }
  report.push('## AI Analysis', '', aiAnalysis, '');
}

report.push('## All Results by Type', '');
for (const [type, results] of Object.entries(summary.results_by_type)) {
  if (results.length > 0) {
    report.push(`### ${type.toUpperCase()}`);
    for (const r of results) {
      const icon = r.passed ? 'PASS' : 'FAIL';
      report.push(`- [${icon}] ${r.test_name}`);
    }
    report.push('');
  }
}

return [{ json: { ...summary, ai_analysis: aiAnalysis, report_md: report.join('\n') } }];

